//! # quicr - Safe Rust FFI Bindings for libquicr
//!
//! This crate provides safe Rust bindings for libquicr, a publish/subscribe
//! transport library based on the IETF MoQ (Media over QUIC) specification.
//! Built on picoquic (QUIC) and picotls (TLS).
//!
//! ## Features
//!
//! - **Async/await** - Built on Embassy async runtime (works on both std and no_std)
//! - **Safe FFI** - Memory-safe wrappers around the C++ libquicr library
//! - **ESP32 Support** - Native support for ESP32 using esp-hal and Embassy
//! - **Minimal Allocations** - Designed for embedded systems with heapless collections
//!
//! ## Platform Support
//!
//! - `std` (default) - Desktop/server platforms with Embassy std backend
//! - `esp-hal` - ESP32 bare-metal with Embassy embedded backend
//!
//! ## Architecture
//!
//! ```text
//! ┌─────────────────────────────────────────────┐
//! │                Application                  │
//! ├─────────────────────────────────────────────┤
//! │     Publisher      │      Subscriber        │
//! ├─────────────────────────────────────────────┤
//! │               Client API                    │
//! ├─────────────────────────────────────────────┤
//! │            libquicr (C++ FFI)               │
//! ├─────────────────────────────────────────────┤
//! │         picoquic     │    picotls           │
//! ├─────────────────────────────────────────────┤
//! │              mbedtls / openssl              │
//! └─────────────────────────────────────────────┘
//! ```
//!
//! ## Quick Start
//!
//! ```rust,ignore
//! use quicr::{ClientBuilder, FullTrackName, ObjectHeaders};
//!
//! // Create and connect client
//! let client = ClientBuilder::new()
//!     .endpoint_id("my-client")
//!     .connect_uri("moqt://relay.example.com:4433")
//!     .build()?;
//!
//! client.connect().await?;
//!
//! // Publish
//! let track = FullTrackName::from_strings(&["audio", "room1"], "mic");
//! let publisher = client.publish(track).await?;
//! let headers = ObjectHeaders::new(0, 0); // group_id, object_id
//! publisher.publish(&headers, &audio_data)?;
//!
//! // Subscribe
//! let track = FullTrackName::from_strings(&["audio", "room1"], "mic");
//! let mut subscriber = client.subscribe(track).await?;
//! loop {
//!     let obj = subscriber.recv().await;
//!     // Handle received data in obj.data
//!     if subscriber.is_done() {
//!         break;
//!     }
//! }
//! ```

#![cfg_attr(not(feature = "std"), no_std)]
#![deny(unsafe_op_in_unsafe_fn)]
#![warn(missing_docs)]

#[cfg(not(feature = "std"))]
extern crate alloc;

// FFI bindings module (generated by bindgen)
pub mod ffi;

// Core modules
pub mod config;
pub mod error;
pub mod runtime;

// Protocol types
pub mod object;
pub mod track;

// Client API
pub mod client;
pub mod publish;
pub mod subscribe;

// Re-exports for convenience
pub use client::{Client, ClientBuilder, ClientCallbackData, ServerSetup, Status};
pub use config::{
    ClientConfig, ClientConfigBuilder, LogLevel, TransportConfig, TransportConfigBuilder,
};
pub use error::{Error, Result};
pub use object::{
    FilterType, GroupOrder, ObjectHeaders, ObjectHeadersBuilder, ObjectStatus, ReceivedObject,
    TrackMode,
};
pub use publish::{
    PublishCallbackData, PublishObjectStatus, PublishStatus, PublishTrack, PublishTrackBuilder,
    Publisher,
};
pub use subscribe::{
    SubscribeCallbackData, SubscribeStatus, SubscribeTrack, SubscribeTrackBuilder, Subscription,
};
pub use track::{FullTrackName, TrackNamespace};

// Re-export runtime types needed for callback data
pub use runtime::{Channel, DynReceiver, DynSender, Signal, TryReceiveError};

// Re-export bytes crate for convenience
pub use bytes::Bytes;

/// Prelude module for convenient imports
pub mod prelude {
    pub use crate::client::{Client, ClientBuilder, Status};
    pub use crate::config::{ClientConfig, LogLevel, TransportConfig};
    pub use crate::error::{Error, Result};
    pub use crate::object::{
        FilterType, GroupOrder, ObjectHeaders, ObjectStatus, ReceivedObject, TrackMode,
    };
    pub use crate::publish::{PublishObjectStatus, PublishStatus, PublishTrack, Publisher};
    pub use crate::subscribe::{SubscribeStatus, SubscribeTrack, Subscription};
    pub use crate::track::{FullTrackName, TrackNamespace};
}
